package com.school.security;
import com.school.entity.User; import com.school.repository.UserRepository; import org.springframework.security.core.authority.SimpleGrantedAuthority; import org.springframework.security.core.userdetails.*; import org.springframework.stereotype.Service;
@Service public class DatabaseUserDetailsService implements UserDetailsService { private final UserRepository users; public DatabaseUserDetailsService(UserRepository users){this.users=users;} public UserDetails loadUserByUsername(String username){User u=users.findByUsername(username).orElseThrow(()->new UsernameNotFoundException("Invalid username or password")); return org.springframework.security.core.userdetails.User.withUsername(u.getUsername()).password(u.getPassword()).authorities(u.getRoles().stream().map(r->new SimpleGrantedAuthority("ROLE_"+r.name())).toList()).disabled(!u.isActive()).build();} }
